package com.shortlink.qr;

import com.google.zxing.BarcodeFormat;
import com.google.zxing.EncodeHintType;
import com.google.zxing.WriterException;
import com.google.zxing.client.j2se.MatrixToImageWriter;
import com.google.zxing.common.BitMatrix;
import com.google.zxing.qrcode.QRCodeWriter;
import com.google.zxing.qrcode.decoder.ErrorCorrectionLevel;

import java.io.ByteArrayOutputStream;
import java.io.IOException;
import java.util.HashMap;
import java.util.Map;

public class QrCodeGenerator {

    private static final int DEFAULT_WIDTH = 300;
    private static final int DEFAULT_HEIGHT = 300;
    private static final String IMAGE_FORMAT = "PNG";

    public byte[] generateQrCode(String url) throws WriterException, IOException {
        return generateQrCode(url, DEFAULT_WIDTH, DEFAULT_HEIGHT);
    }

    public byte[] generateQrCode(String url, int width, int height) throws WriterException, IOException {
        Map<EncodeHintType, Object> hints = new HashMap<>();
        hints.put(EncodeHintType.ERROR_CORRECTION, ErrorCorrectionLevel.M);
        hints.put(EncodeHintType.CHARACTER_SET, "UTF-8");
        hints.put(EncodeHintType.MARGIN, 1);

        QRCodeWriter qrCodeWriter = new QRCodeWriter();
        BitMatrix bitMatrix = qrCodeWriter.encode(url, BarcodeFormat.QR_CODE, width, height, hints);

        ByteArrayOutputStream outputStream = new ByteArrayOutputStream();
        MatrixToImageWriter.writeToStream(bitMatrix, IMAGE_FORMAT, outputStream);

        return outputStream.toByteArray();
    }
}

package com.shortlink.service;

import org.springframework.stereotype.Service;

import java.util.Map;
import java.util.Optional;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class ShortLinkService {

    private final Map<String, String> shortLinkStore = new ConcurrentHashMap<>();

    public ShortLinkService() {
        shortLinkStore.put("abc123", "https://example.com/very-long-url");
        shortLinkStore.put("def456", "https://example.com/another-long-url");
    }

    public Optional<String> resolveShortLink(String code) {
        return Optional.ofNullable(shortLinkStore.get(code));
    }

    public String createShortLink(String url, String code) {
        shortLinkStore.put(code, url);
        return code;
    }
}

package com.shortlink.controller;

import com.google.zxing.WriterException;
import com.shortlink.qr.QrCodeGenerator;
import com.shortlink.service.ShortLinkService;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RestController;

import java.io.IOException;

@RestController
public class QrCodeController {

    private final ShortLinkService shortLinkService;
    private final QrCodeGenerator qrCodeGenerator;

    public QrCodeController(ShortLinkService shortLinkService) {
        this.shortLinkService = shortLinkService;
        this.qrCodeGenerator = new QrCodeGenerator();
    }

    @GetMapping("/s/{code}/qr")
    public ResponseEntity<byte[]> getQrCode(@PathVariable String code) {
        return shortLinkService.resolveShortLink(code)
                .map(url -> {
                    try {
                        byte[] qrCodeImage = qrCodeGenerator.generateQrCode(url);

                        HttpHeaders headers = new HttpHeaders();
                        headers.setContentType(MediaType.IMAGE_PNG);
                        headers.setContentLength(qrCodeImage.length);

                        return new ResponseEntity<>(qrCodeImage, headers, HttpStatus.OK);
                    } catch (WriterException | IOException e) {
                        return new ResponseEntity<byte[]>(HttpStatus.INTERNAL_SERVER_ERROR);
                    }
                })
                .orElse(new ResponseEntity<>(HttpStatus.NOT_FOUND));
    }
}

package com.shortlink.qr;

import com.google.zxing.WriterException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;

import static org.junit.jupiter.api.Assertions.*;

class QrCodeGeneratorTest {

    private QrCodeGenerator qrCodeGenerator;

    @BeforeEach
    void setUp() {
        qrCodeGenerator = new QrCodeGenerator();
    }

    @Test
    void testGenerateQrCode_ValidUrl_ReturnsPngBytes() throws WriterException, IOException {
        String url = "https://example.com";

        byte[] result = qrCodeGenerator.generateQrCode(url);

        assertNotNull(result);
        assertTrue(result.length > 0);
        assertTrue(isPngImage(result));
    }

    @Test
    void testGenerateQrCode_CustomDimensions_ReturnsPngBytes() throws WriterException, IOException {
        String url = "https://example.com";
        int width = 400;
        int height = 400;

        byte[] result = qrCodeGenerator.generateQrCode(url, width, height);

        assertNotNull(result);
        assertTrue(result.length > 0);
        assertTrue(isPngImage(result));
    }

    @Test
    void testGenerateQrCode_LongUrl_ReturnsPngBytes() throws WriterException, IOException {
        String url = "https://example.com/very/long/path/with/many/segments/and/query?param1=value1&param2=value2";

        byte[] result = qrCodeGenerator.generateQrCode(url);

        assertNotNull(result);
        assertTrue(result.length > 0);
        assertTrue(isPngImage(result));
    }

    @Test
    void testGenerateQrCode_EmptyUrl_ThrowsException() {
        String url = "";

        assertThrows(WriterException.class, () -> {
            qrCodeGenerator.generateQrCode(url);
        });
    }

    private boolean isPngImage(byte[] data) {
        if (data == null || data.length < 8) {
            return false;
        }
        return data[0] == (byte) 0x89 && 
               data[1] == (byte) 0x50 && 
               data[2] == (byte) 0x4E && 
               data[3] == (byte) 0x47 &&
               data[4] == (byte) 0x0D &&
               data[5] == (byte) 0x0A &&
               data[6] == (byte) 0x1A &&
               data[7] == (byte) 0x0A;
    }
}

package com.shortlink.controller;

import com.shortlink.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;

import java.util.Optional;

import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(QrCodeController.class)
class QrCodeControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService shortLinkService;

    @Test
    void testGetQrCode_ValidCode_ReturnsOkWithPngImage() throws Exception {
        String code = "abc123";
        String url = "https://example.com";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(header().exists("Content-Length"))
                .andExpect(content().bytes(org.hamcrest.Matchers.notNullValue()));
    }

    @Test
    void testGetQrCode_InvalidCode_ReturnsNotFound() throws Exception {
        String code = "invalid";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.empty());

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isNotFound());
    }

    @Test
    void testGetQrCode_ValidCode_ResponseHeadersCorrect() throws Exception {
        String code = "def456";
        String url = "https://example.com/test";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(header().string("Content-Type", "image/png"))
                .andExpect(header().exists("Content-Length"));
    }

    @Test
    void testGetQrCode_DifferentCodes_GeneratesDifferentQrCodes() throws Exception {
        String code1 = "code1";
        String code2 = "code2";
        String url1 = "https://example.com/url1";
        String url2 = "https://example.com/url2";

        when(shortLinkService.resolveShortLink(code1)).thenReturn(Optional.of(url1));
        when(shortLinkService.resolveShortLink(code2)).thenReturn(Optional.of(url2));

        byte[] qr1 = mockMvc.perform(get("/s/{code}/qr", code1))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        byte[] qr2 = mockMvc.perform(get("/s/{code}/qr", code2))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        org.junit.jupiter.api.Assertions.assertNotEquals(qr1.length, qr2.length);
    }
}

package com.shortlink.qr;

import com.google.zxing.WriterException;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.io.IOException;

import static org.assertj.core.api.Assertions.*;

class QrCodeGeneratorTest {

    private QrCodeGenerator qrCodeGenerator;

    @BeforeEach
    void setUp() {
        qrCodeGenerator = new QrCodeGenerator();
    }

    @Test
    void generateQrCodeWithValidUrl_producesNonEmptyPngBytes() throws WriterException, IOException {
        String url = "https://example.com";

        byte[] result = qrCodeGenerator.generateQrCode(url);

        assertThat(result).isNotEmpty();
        assertThat(isPngImage(result)).isTrue();
    }

    @Test
    void generateQrCodeWithCustomDimensions_producesNonEmptyPngBytes() throws WriterException, IOException {
        String url = "https://example.com";
        int width = 400;
        int height = 400;

        byte[] result = qrCodeGenerator.generateQrCode(url, width, height);

        assertThat(result).isNotEmpty();
        assertThat(isPngImage(result)).isTrue();
    }

    @Test
    void generateQrCodeWithLongUrl_producesNonEmptyPngBytes() throws WriterException, IOException {
        String url = "https://example.com/very/long/path/with/many/segments/and/query?param1=value1&param2=value2&param3=value3&param4=value4";

        byte[] result = qrCodeGenerator.generateQrCode(url);

        assertThat(result).isNotEmpty();
        assertThat(isPngImage(result)).isTrue();
    }

    @Test
    void generateQrCodeWithEmptyString_throwsException() {
        String url = "";

        assertThatThrownBy(() -> qrCodeGenerator.generateQrCode(url))
                .isInstanceOf(WriterException.class);
    }

    @Test
    void generateQrCodeWithNullUrl_throwsException() {
        assertThatThrownBy(() -> qrCodeGenerator.generateQrCode(null))
                .isInstanceOf(NullPointerException.class);
    }

    @Test
    void generateQrCodeWithZeroDimensions_throwsException() {
        String url = "https://example.com";

        assertThatThrownBy(() -> qrCodeGenerator.generateQrCode(url, 0, 0))
                .isInstanceOf(IllegalArgumentException.class);
    }

    @Test
    void generateQrCodeWithNegativeDimensions_throwsException() {
        String url = "https://example.com";

        assertThatThrownBy(() -> qrCodeGenerator.generateQrCode(url, -100, -100))
                .isInstanceOf(IllegalArgumentException.class);
    }

    @Test
    void generateQrCodeWithExtremelyLargeUrl_handlesGracefully() {
        String url = "https://example.com/" + "a".repeat(3000);

        assertThatThrownBy(() -> qrCodeGenerator.generateQrCode(url))
                .isInstanceOfAny(WriterException.class, IllegalArgumentException.class);
    }

    @Test
    void generateQrCodeWithSpecialCharactersInUrl_producesValidPng() throws WriterException, IOException {
        String url = "https://example.com/path?param=value&other=测试";

        byte[] result = qrCodeGenerator.generateQrCode(url);

        assertThat(result).isNotEmpty();
        assertThat(isPngImage(result)).isTrue();
    }

    @Test
    void generateQrCodeTwiceWithSameUrl_producesIdenticalResults() throws WriterException, IOException {
        String url = "https://example.com/test";

        byte[] result1 = qrCodeGenerator.generateQrCode(url);
        byte[] result2 = qrCodeGenerator.generateQrCode(url);

        assertThat(result1).isEqualTo(result2);
    }

    private boolean isPngImage(byte[] data) {
        if (data == null || data.length < 8) {
            return false;
        }
        return data[0] == (byte) 0x89 && 
               data[1] == (byte) 0x50 && 
               data[2] == (byte) 0x4E && 
               data[3] == (byte) 0x47 &&
               data[4] == (byte) 0x0D &&
               data[5] == (byte) 0x0A &&
               data[6] == (byte) 0x1A &&
               data[7] == (byte) 0x0A;
    }
}

package com.shortlink.controller;

import com.shortlink.service.ShortLinkService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.web.servlet.WebMvcTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.http.MediaType;
import org.springframework.test.web.servlet.MockMvc;
import org.springframework.test.web.servlet.MvcResult;

import java.util.Optional;

import static org.assertj.core.api.Assertions.*;
import static org.mockito.Mockito.when;
import static org.springframework.test.web.servlet.request.MockMvcRequestBuilders.get;
import static org.springframework.test.web.servlet.result.MockMvcResultMatchers.*;

@WebMvcTest(QrCodeController.class)
class QrCodeControllerTest {

    @Autowired
    private MockMvc mockMvc;

    @MockBean
    private ShortLinkService shortLinkService;

    @Test
    void getQrCodeForValidShortLink_returns200WithPngContentType() throws Exception {
        String code = "abc123";
        String url = "https://example.com";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG))
                .andExpect(header().exists("Content-Length"));
    }

    @Test
    void getQrCodeForValidShortLink_returnsNonEmptyImageData() throws Exception {
        String code = "abc123";
        String url = "https://example.com";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        MvcResult result = mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andReturn();

        byte[] content = result.getResponse().getContentAsByteArray();
        assertThat(content).isNotEmpty();
    }

    @Test
    void getQrCodeForNonExistentShortLink_returns404() throws Exception {
        String code = "nonexistent";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.empty());

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isNotFound());
    }

    @Test
    void getQrCodeForNonExistentShortLink_returnsNoContent() throws Exception {
        String code = "invalid123";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.empty());

        MvcResult result = mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isNotFound())
                .andReturn();

        byte[] content = result.getResponse().getContentAsByteArray();
        assertThat(content).isEmpty();
    }

    @Test
    void getQrCodeForEmptyCode_returns404() throws Exception {
        String code = "";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.empty());

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isNotFound());
    }

    @Test
    void getQrCodeWithSpecialCharactersInCode_handlesCorrectly() throws Exception {
        String code = "test-code_123";
        String url = "https://example.com";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG));
    }

    @Test
    void getQrCodeMultipleTimesForSameCode_producesConsistentResults() throws Exception {
        String code = "consistent";
        String url = "https://example.com/test";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        byte[] firstResult = mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        byte[] secondResult = mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        assertThat(firstResult).isEqualTo(secondResult);
    }

    @Test
    void getQrCodeForDifferentCodes_producesDifferentImages() throws Exception {
        String code1 = "code1";
        String code2 = "code2";
        String url1 = "https://example.com/first";
        String url2 = "https://example.com/second";

        when(shortLinkService.resolveShortLink(code1)).thenReturn(Optional.of(url1));
        when(shortLinkService.resolveShortLink(code2)).thenReturn(Optional.of(url2));

        byte[] qr1 = mockMvc.perform(get("/s/{code}/qr", code1))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        byte[] qr2 = mockMvc.perform(get("/s/{code}/qr", code2))
                .andExpect(status().isOk())
                .andReturn()
                .getResponse()
                .getContentAsByteArray();

        assertThat(qr1).isNotEqualTo(qr2);
    }

    @Test
    void getQrCodeResponseHeaders_includeCorrectContentTypeAndLength() throws Exception {
        String code = "test";
        String url = "https://example.com";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(header().string("Content-Type", "image/png"))
                .andExpect(header().exists("Content-Length"))
                .andExpect(header().longValue("Content-Length", org.hamcrest.Matchers.greaterThan(0L)));
    }

    @Test
    void getQrCodeForUrlWithQueryParameters_generatesValidQrCode() throws Exception {
        String code = "params";
        String url = "https://example.com/path?param1=value1&param2=value2";

        when(shortLinkService.resolveShortLink(code)).thenReturn(Optional.of(url));

        mockMvc.perform(get("/s/{code}/qr", code))
                .andExpect(status().isOk())
                .andExpect(content().contentType(MediaType.IMAGE_PNG));
    }
}
